const SORTED_TRANSLATION_KEYS:Record<'en'|'de',Array<[string,string]>>={
 en:Object.entries(TRANSLATIONS.en).sort((a,b)=>b[0].length-a[0].length),
 de:Object.entries(TRANSLATIONS.de).sort((a,b)=>b[0].length-a[0].length)
};
const SORTED_REVERSE_KEYS:Record<'en'|'de',Array<[string,string]>>={
 en:Object.entries(TRANSLATIONS.en).filter(([,v])=>Boolean(v)).sort((a,b)=>b[1].length-a[1].length),
 de:Object.entries(TRANSLATIONS.de).filter(([,v])=>Boolean(v)).sort((a,b)=>b[1].length-a[1].length)
};
const REVERSE_EXACT:Record<'en'|'de',Map<string,string>>={
 en:new Map(SORTED_REVERSE_KEYS.en.map(([cs,value])=>[value,cs])),
 de:new Map(SORTED_REVERSE_KEYS.de.map(([cs,value])=>[value,cs]))
};
function canonicalizeText(text:string){
 // Reverse translation must only match the whole text. Replacing translated
 // fragments inside words caused strings such as "Exportovatovat...".
 const leading=text.match(/^\s*/)?.[0]||'';
 const trailing=text.match(/\s*$/)?.[0]||'';
 const core=text.slice(leading.length,text.length-trailing.length);
 const exact=REVERSE_EXACT.en.get(core)||REVERSE_EXACT.de.get(core);
 return exact?leading+exact+trailing:text;
}
function translateText(text:string,lang:Lang){
 const canonical=canonicalizeText(text);
 if(lang==='cs')return canonical;
 let result=canonical;
 for(const [key,value] of SORTED_TRANSLATION_KEYS[lang]){
  if(result.includes(key))result=result.split(key).join(value);
 }
 if(lang==='en'){
  result=result.replace(/Chybí\s+(\d+)\s+dokument\(y\)\./g,'$1 document(s) missing.');
  result=result.replace(/Událost\s+(PU-[\d-]+)\s+byla vytvořena\./g,'Claim $1 was created.');
  result=result.replace(/Rozhodnutí „(.+?)“ bylo uloženo jako návrh\./g,'Decision “$1” was saved as a draft.');
 }else if(lang==='de'){
  result=result.replace(/Chybí\s+(\d+)\s+dokument\(y\)\./g,'$1 Dokument(e) fehlen.');
  result=result.replace(/Událost\s+(PU-[\d-]+)\s+byla vytvořena\./g,'Der Schadenfall $1 wurde erstellt.');
  result=result.replace(/Rozhodnutí „(.+?)“ bylo uloženo jako návrh\./g,'Die Entscheidung „$1“ wurde als Entwurf gespeichert.');
 }
 return result;
}
const DOM_ORIGINALS=new WeakMap<Node,string>();
const ATTRS=['placeholder','title','aria-label','alt'] as const;
function translateElementTree(root:Node,lang:Lang){
 const processText=(node:Node)=>{
  const current=node.textContent||'';
  if(!current.trim())return;
  // Keep an immutable Czech source for each DOM text node. MutationObserver
  // can observe our own update later; translating from the stored source makes
  // the operation idempotent and prevents text from growing on every pass.
  let canonical=DOM_ORIGINALS.get(node);
  if(canonical===undefined){
   canonical=canonicalizeText(current);
   DOM_ORIGINALS.set(node,canonical);
  }
  const translated=translateText(canonical,lang);
  if(current!==translated)node.textContent=translated;
 };
 const processElement=(el:Element)=>{
  if(el.closest('.language-switcher'))return;
  for(const attr of ATTRS){
   const current=el.getAttribute(attr);
   if(!current)continue;
   const key=`data-i18n-${attr}`;
   const canonical=canonicalizeText(el.getAttribute(key)||current);
   if(!el.hasAttribute(key))el.setAttribute(key,canonical);
   const translated=translateText(canonical,lang);
   if(current!==translated)el.setAttribute(attr,translated);
  }
 };
 if(root.nodeType===Node.TEXT_NODE){processText(root);return;}
 if(root.nodeType!==Node.ELEMENT_NODE&&root.nodeType!==Node.DOCUMENT_FRAGMENT_NODE)return;
 if(root.nodeType===Node.ELEMENT_NODE)processElement(root as Element);
 const walker=document.createTreeWalker(root,NodeFilter.SHOW_ELEMENT|NodeFilter.SHOW_TEXT);
 let node=walker.nextNode();
 while(node){
  if(node.nodeType===Node.TEXT_NODE)processText(node);
  else processElement(node as Element);
  node=walker.nextNode();
 }
}
function useDomTranslation(lang:Lang){useEffect(()=>{
 document.documentElement.lang=lang;
 document.title=translateText('KLIK · Kooperativní likvidační informační komplex',lang);
 let scheduled=false;
 const queued=new Set<Node>();
 let selfUpdate=false;
 const flush=()=>{
  scheduled=false;
  if(!queued.size)return;
  selfUpdate=true;
  const batch=[...queued];queued.clear();
  for(const node of batch){
   if(document.body.contains(node)||node===document.body)translateElementTree(node,lang);
  }
  selfUpdate=false;
 };
 const schedule=(node:Node)=>{
  queued.add(node);
  if(scheduled)return;
  scheduled=true;
  const run=()=>window.requestAnimationFrame(flush);
  if('requestIdleCallback' in window)(window as any).requestIdleCallback(run,{timeout:120});
  else window.setTimeout(run,16);
 };
 translateElementTree(document.body,lang);
 const observer=new MutationObserver(records=>{
  if(selfUpdate)return;
  for(const record of records){
   if(record.type==='childList')record.addedNodes.forEach(schedule);
   else if(record.type==='characterData')schedule(record.target);
   else if(record.type==='attributes')schedule(record.target);
  }
 });
 observer.observe(document.body,{childList:true,subtree:true,characterData:true,attributes:true,attributeFilter:[...ATTRS]});
 return()=>{observer.disconnect();queued.clear()};
},[lang]);}
function LanguageSwitcher({lang,setLang}:{lang:Lang,setLang:(l:Lang)=>void}){return <div className="language-switcher" role="group" aria-label="Language"><span className="language-icon">🌐</span>{(['cs','en','de'] as Lang[]).map(l=><button key={l} className={lang===l?'active':''} onClick={()=>setLang(l)} aria-pressed={lang===l}>{l.toUpperCase()}<small>{LANGUAGE_LABELS[l]}</small></button>)}</div>}

