 if(kind==='new'){const create=()=>{if(!form.client?.trim()||!form.description?.trim()){setError('Vyplňte klienta a popis události.');setStep(2);return}const id='PU-2026-'+String(5000+claims.length).padStart(6,'0');const c:Claim={...baseClaims[0],id,client:form.client,product:form.product||'Vozidlo',description:form.description,status:'Registrováno',priority:'Střední',eventDate:form.eventDate||new Date().toLocaleDateString('cs-CZ'),reported:new Date().toLocaleDateString('cs-CZ'),estimate:Number(form.estimate)||0,reserve:Number(form.estimate)||0,paid:0,missing:form.file?0:1,activity:'právě teď',email:form.email||'demo@example.test',phone:form.phone||'+420 777 000 000'};setClaims([c,...claims]);setTasks([{id:uid(),title:'Provést počáteční kontrolu',claimId:id,due:'Zítra',priority:'Střední',done:false},...tasks]);audit('Vytvoření události',`Vytvořena ${id}`,id);done(`Událost ${id} byla vytvořena.`)};return shell('Nová pojistná událost',<>{step===1&&<div><h3>Kanál oznámení</h3><div className="choice-grid">{['Telefon','E-mail','Pobočka','Mobilní aplikace','Klientská zóna','API'].map(x=><button key={x} className={form.channel===x?'selected':''} onClick={()=>setForm({...form,channel:x})}>{x}</button>)}</div></div>}{step===2&&<div className="form-grid"><label>Klient<input value={form.client||''} onChange={e=>setForm({...form,client:e.target.value})}/></label><label>Produkt<select value={form.product||'Vozidlo'} onChange={e=>setForm({...form,product:e.target.value})}>{['Vozidlo','Majetek','Cestovní','Životní a úrazové','Odpovědnost','Podnikatelé'].map(x=><option key={x}>{x}</option>)}</select></label><label>Datum škody<input type="date" value={form.eventDate||''} onChange={e=>setForm({...form,eventDate:e.target.value})}/></label><label>Odhad škody<input type="number" value={form.estimate||''} onChange={e=>setForm({...form,estimate:e.target.value})}/></label><label className="full">Popis události<textarea value={form.description||''} onChange={e=>setForm({...form,description:e.target.value})}/></label>{error&&<p className="form-error full">{error}</p>}</div>}{step===3&&<UploadControl onFile={f=>setForm({...form,file:f})}/>} {step===4&&<div className="summary-box"><CheckCircle2/><h3>Rekapitulace</h3><p><b>{form.client}</b><br/>{form.product} · {form.description}</p></div>}</>,<><button className="secondary" onClick={step===1?close:()=>setStep(step-1)}>{step===1?'Zrušit':'Zpět'}</button>{step<4?<button className="primary" onClick={()=>{if(step===1&&!form.channel){setError('Vyberte kanál oznámení.');return}setError('');setStep(step+1)}}>Pokračovat<ChevronRight/></button>:<button className="primary" onClick={create}>Vytvořit událost</button>}</>,true)}
 if(kind==='upload'){return shell('Nahrát dokument',<><label>Případ<select value={form.claimId||claims[0]?.id} onChange={e=>setForm({...form,claimId:e.target.value})}>{claims.map((c:Claim)=><option key={c.id}>{c.id}</option>)}</select></label><label>Typ dokumentu<select value={form.type||'Příloha'} onChange={e=>setForm({...form,type:e.target.value})}><option>Příloha</option><option>Protokol</option><option>Rozpočet</option><option>Fotografie</option></select></label><UploadControl onFile={f=>setForm({...form,file:f})}/>{error&&<p className="form-error">{error}</p>}</>,cancelSave(async()=>{if(!form.file){setError('Vyberte soubor.');return}const content=await fileToDataUrl(form.file);const d:Doc={id:uid(),name:form.file.name,type:form.type||'Příloha',claimId:form.claimId||claims[0].id,status:'Čeká na kontrolu',size:formatBytes(form.file.size),mime:form.file.type,content};setDocs([d,...docs]);audit('Nahrání dokumentu',d.name,d.claimId);done('Dokument byl nahrán.')}))}
